// Parsear respuesta de Claude (sea cual sea el NSE branch)
const aiResp = $input.first().json;
const rawText = aiResp.content?.[0]?.text || '{}';
const leadData = $('💾 Extraer Datos Lead').first().json;

let email = {};
try {
  const cleaned = rawText.replace(/```json/gi,'').replace(/```/gi,'').trim();
  email = JSON.parse(cleaned);
} catch(e) {
  email = { subject: `Eight Academy × ${leadData.lead_name}`, whatsapp_message: rawText.substring(0,500), follow_up_days: 5 };
}

return [{ json: {
  ...leadData,
  email_subject: email.subject || '',
  whatsapp_msg: email.whatsapp_message || '',
  email_html: email.email_body_html || '',
  email_text: email.email_body_text || '',
  value_prop: email.value_prop_personalizada || '',
  cta: email.cta || '',
  promo_angle: email.promo_angle || '',
  follow_up_days: email.follow_up_days || 5,
  outreach_date: new Date().toISOString()
}}];

